const m = $json;

// El trigger de Outlook puede entregar el correo "simplificado" (from es un
// string, to es [string], solo bodyPreview) o completo (from.emailAddress.address,
// toRecipients, body.content), segun el toggle "Simplify" del nodo. Soporta ambos.
const dir = (v) => (typeof v === 'string' ? v : (v?.emailAddress?.address ?? ''));

const remitente = dir(m.from) || dir(m.sender) || '';

// Correos sin remitente real (notificaciones del propio Microsoft, avisos del
// sistema) no son consultas de clientes: se descartan para que no lleguen al
// cerebro. Devolver [] corta el flujo para este item, sin marcarlo como error.
if (!remitente) return [];

const cuentaSoporte =
  (Array.isArray(m.to) ? m.to[0] : '') ||
  (m.toRecipients?.[0]?.emailAddress?.address ?? '') ||
  '';

// Las respuestas que envia el propio asistente salen desde la cuenta de soporte;
// si el trigger las levanta (p.ej. quedan en Enviados o el buzon es compartido),
// no deben reprocesarse: causarian un bucle de auto-respuesta. Se descartan aqui
// ademas de la guarda equivalente en el cerebro.
if (cuentaSoporte && remitente.trim().toLowerCase() === cuentaSoporte.trim().toLowerCase()) return [];

return [{
  json: {
    hiloId: m.conversationId,
    mensajeId: m.id,
    remitente,
    cuentaSoporte,
    asunto: m.subject ?? '',
    cuerpo: m.body?.content ?? m.bodyPreview ?? '',
    adjuntos: [],
  },
}];
